// ── SVG Equity Curve ────────────────────────────────────────────────────
function EquityCurve({ data, isMobile }) {
  const W = isMobile ? 340 : 560;
  const H = isMobile ? 160 : 200;
  const PAD = { top: 20, right: 12, bottom: 24, left: 60 };

  const points = useMemo(() => {
    if (!data || data.length === 0) return [];
    return data.map(d => ({
      ts: d.ts || d.timestamp || d.t || 0,
      eq: d.equity ?? d.value ?? d.eq ?? 0,
    }));
  }, [data]);

  if (points.length === 0) {
    return (
      <div className={s.equityEmpty} style={{ height: H }}>
        No equity data yet
      </div>
    );
  }

  const eqs = points.map(p => p.eq);
  const minEq = Math.min(...eqs);
  const maxEq = Math.max(...eqs);
  const range = (maxEq - minEq) || 1;
  const curEq = eqs[eqs.length - 1];
  const isUp = curEq >= eqs[0];

  const chartW = W - PAD.left - PAD.right;
  const chartH = H - PAD.top - PAD.bottom;

  const toX = (i) => PAD.left + (i / Math.max(points.length - 1, 1)) * chartW;
  const toY = (eq) => PAD.top + chartH - ((eq - minEq) / range) * chartH;

  const pathD = points.map((p, i) =>
    `${i === 0 ? 'M' : 'L'} ${toX(i).toFixed(1)} ${toY(p.eq).toFixed(1)}`
  ).join(' ');

  const fillD = pathD
    + ` L ${toX(points.length - 1).toFixed(1)} ${(PAD.top + chartH).toFixed(1)}`
    + ` L ${PAD.left.toFixed(1)} ${(PAD.top + chartH).toFixed(1)} Z`;

  const lineColor = isUp ? C.green : C.red;

  // Y-axis labels (5 ticks)
  const yTicks = Array.from({ length: 5 }, (_, i) => {
    const val = minEq + (range * i) / 4;
    return { val, y: toY(val) };
  });

  return (
    <svg viewBox={`0 0 ${W} ${H}`} style={{ width: '100%', maxWidth: W, height: 'auto' }}>
      {/* Grid lines */}
      {yTicks.map((t, i) => (
        <g key={i}>
          <line
            x1={PAD.left} y1={t.y} x2={W - PAD.right} y2={t.y}
            stroke="rgba(255,255,255,0.04)" strokeWidth={1}
          />
          <text
            x={PAD.left - 6} y={t.y + 3}
            textAnchor="end" fill={C.textSecondary}
            fontSize={9} fontFamily={mono}
          >
            {t.val >= 10000 ? `${(t.val / 1000).toFixed(0)}k` : fmtNum(t.val, 0)}
          </text>
        </g>
      ))}

      {/* Gradient fill */}
      <defs>
        <linearGradient id="eqFill" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={lineColor} stopOpacity={0.2} />
          <stop offset="100%" stopColor={lineColor} stopOpacity={0} />
        </linearGradient>
      </defs>
      <path d={fillD} fill="url(#eqFill)" />
      <path d={pathD} fill="none" stroke={lineColor} strokeWidth={2} strokeLinejoin="round" />

      {/* Current dot */}
      <circle
        cx={toX(points.length - 1)} cy={toY(curEq)}
        r={4} fill={lineColor} stroke={C.surface} strokeWidth={2}
      />

      {/* Min / Max / Current labels */}
      <text
        x={W - PAD.right} y={PAD.top - 6}
        textAnchor="end" fill={C.textSecondary} fontSize={9} fontFamily={mono}
      >
        High: {fmt$(maxEq)}
      </text>
      <text
        x={W - PAD.right} y={PAD.top + chartH + 16}
        textAnchor="end" fill={C.textSecondary} fontSize={9} fontFamily={mono}
      >
        Low: {fmt$(minEq)}
      </text>
      <text
        x={PAD.left} y={PAD.top - 6}
        textAnchor="start" fill={lineColor} fontSize={10} fontFamily={mono} fontWeight={700}
      >
        Current: {fmt$(curEq)}
      </text>
    </svg>
  );
}

