/* ═══════════════════════════════════════════════════════════════════════════
   ConversionModal — Upgrade modal triggered by paper trading milestones
   Shows contextual messaging based on trigger type:
   - first_profit: celebration glow
   - five_trades: stats display (trade count, win rate)
   - day_one: timer display (hours active)
   Primary CTA triggers Stripe checkout. Secondary dismisses.
   ═══════════════════════════════════════════════════════════════════════════ */
import { useEffect, useRef } from 'react';
import { tokens } from '../styles/tokens';
import useStripeCheckout from '../hooks/useStripeCheckout';

const mono = tokens.font.mono;
const body = tokens.font.sans;

/**
 * @param {Object} props
 * @param {Object} props.trigger - { type, title, body, cta, secondary, stats?, hoursActive? }
 * @param {Function} props.onDismiss - Called when user clicks secondary or overlay
 */
export default function ConversionModal({ trigger, onDismiss }) {
  const { checkout, loading, error } = useStripeCheckout();
  const overlayRef = useRef(null);

  // Close on Escape key
  useEffect(() => {
    const handler = (e) => { if (e.key === 'Escape') onDismiss(); };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [onDismiss]);

  if (!trigger) return null;

  const isFirstProfit = trigger.type === 'first_profit';
  const isFiveTrades = trigger.type === 'five_trades';
  const isDayOne = trigger.type === 'day_one';

  // Accent colors by trigger type
  const accentColor = isFirstProfit ? tokens.color.green
    : isFiveTrades ? tokens.color.blue
    : tokens.color.purple;

  return (
    <div
      ref={overlayRef}
      onClick={(e) => { if (e.target === overlayRef.current) onDismiss(); }}
      style={{
        position: 'fixed',
        inset: 0,
        zIndex: 9999,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'rgba(0,0,0,0.6)',
        backdropFilter: 'blur(8px)',
        WebkitBackdropFilter: 'blur(8px)',
        animation: 'fadeIn 200ms ease',
      }}
    >
      <div style={{
        maxWidth: 440,
        width: '90%',
        background: 'linear-gradient(135deg, rgba(15,22,32,0.98), rgba(11,15,20,0.98))',
        border: `1px solid ${accentColor}22`,
        borderRadius: tokens.radius.xl,
        padding: '36px 32px',
        position: 'relative',
        overflow: 'hidden',
        boxShadow: `0 24px 80px rgba(0,0,0,0.5), 0 0 40px ${accentColor}10`,
      }}>

        {/* Celebration glow for first profit */}
        {isFirstProfit && (
          <div style={{
            position: 'absolute', top: -80, left: '50%', transform: 'translateX(-50%)',
            width: 300, height: 300, borderRadius: '50%',
            background: `radial-gradient(circle, ${tokens.color.green}15 0%, transparent 70%)`,
            pointerEvents: 'none',
            animation: 'pulse 2s ease-in-out infinite',
          }} />
        )}

        {/* Icon */}
        <div style={{
          textAlign: 'center', marginBottom: 20, position: 'relative',
        }}>
          {isFirstProfit && (
            <div style={{
              width: 56, height: 56, borderRadius: 14,
              margin: '0 auto',
              background: `rgba(34,197,94,0.12)`,
              border: '2px solid rgba(34,197,94,0.25)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 24,
            }}>
              <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke={tokens.color.green} strokeWidth="2">
                <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z" />
              </svg>
            </div>
          )}
          {isFiveTrades && (
            <div style={{
              width: 56, height: 56, borderRadius: 14,
              margin: '0 auto',
              background: `rgba(96,165,250,0.12)`,
              border: '2px solid rgba(96,165,250,0.25)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
            }}>
              <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke={tokens.color.blue} strokeWidth="2">
                <polyline points="22 12 18 12 15 21 9 3 6 12 2 12" />
              </svg>
            </div>
          )}
          {isDayOne && (
            <div style={{
              width: 56, height: 56, borderRadius: 14,
              margin: '0 auto',
              background: `rgba(167,139,250,0.12)`,
              border: '2px solid rgba(167,139,250,0.25)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
            }}>
              <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke={tokens.color.purple} strokeWidth="2">
                <circle cx="12" cy="12" r="10" />
                <polyline points="12 6 12 12 16 14" />
              </svg>
            </div>
          )}
        </div>

        {/* Title */}
        <h2 style={{
          fontFamily: body, fontSize: 22, fontWeight: 800,
          color: tokens.color.text, textAlign: 'center',
          margin: '0 0 10px', letterSpacing: '-0.01em',
        }}>
          {trigger.title}
        </h2>

        {/* Body */}
        <p style={{
          fontFamily: body, fontSize: 14, color: tokens.color.textSecondary,
          textAlign: 'center', margin: '0 0 20px', lineHeight: 1.6,
        }}>
          {trigger.body}
        </p>

        {/* Stats display for five_trades trigger */}
        {isFiveTrades && trigger.stats && (
          <div style={{
            display: 'flex', justifyContent: 'center', gap: 24,
            marginBottom: 24, padding: '14px 0',
            background: 'rgba(96,165,250,0.04)',
            borderRadius: tokens.radius.md,
            border: '1px solid rgba(96,165,250,0.1)',
          }}>
            <div style={{ textAlign: 'center' }}>
              <div style={{
                fontFamily: mono, fontSize: 22, fontWeight: 800,
                color: tokens.color.blue,
              }}>
                {trigger.stats.tradeCount}
              </div>
              <div style={{
                fontFamily: mono, fontSize: 10, fontWeight: 600,
                color: tokens.color.textSecondary, textTransform: 'uppercase',
                letterSpacing: '0.06em',
              }}>
                Trades
              </div>
            </div>
            <div style={{
              width: 1, background: 'rgba(255,255,255,0.06)',
            }} />
            <div style={{ textAlign: 'center' }}>
              <div style={{
                fontFamily: mono, fontSize: 22, fontWeight: 800,
                color: tokens.color.green,
              }}>
                {trigger.stats.winRate}%
              </div>
              <div style={{
                fontFamily: mono, fontSize: 10, fontWeight: 600,
                color: tokens.color.textSecondary, textTransform: 'uppercase',
                letterSpacing: '0.06em',
              }}>
                Win Rate
              </div>
            </div>
          </div>
        )}

        {/* Timer display for day_one trigger */}
        {isDayOne && trigger.hoursActive && (
          <div style={{
            textAlign: 'center', marginBottom: 24, padding: '14px 0',
            background: 'rgba(167,139,250,0.04)',
            borderRadius: tokens.radius.md,
            border: '1px solid rgba(167,139,250,0.1)',
          }}>
            <div style={{
              fontFamily: mono, fontSize: 28, fontWeight: 800,
              color: tokens.color.purple,
            }}>
              {trigger.hoursActive}h
            </div>
            <div style={{
              fontFamily: mono, fontSize: 10, fontWeight: 600,
              color: tokens.color.textSecondary, textTransform: 'uppercase',
              letterSpacing: '0.06em',
            }}>
              Active Runtime
            </div>
          </div>
        )}

        {/* Primary CTA */}
        <button
          onClick={() => checkout('trader')}
          disabled={loading}
          style={{
            width: '100%',
            padding: '14px 32px',
            borderRadius: tokens.radius.md,
            fontSize: 15,
            fontWeight: 800,
            fontFamily: mono,
            color: '#000',
            border: 'none',
            cursor: loading ? 'wait' : 'pointer',
            background: `linear-gradient(135deg, ${accentColor}, ${accentColor}CC)`,
            boxShadow: `0 4px 20px ${accentColor}25`,
            letterSpacing: '0.02em',
            opacity: loading ? 0.7 : 1,
            transition: tokens.transition.fast,
            marginBottom: 10,
          }}
        >
          {loading ? 'Redirecting...' : trigger.cta}
        </button>

        {error && (
          <div style={{
            fontFamily: body, fontSize: 12, color: tokens.color.red,
            textAlign: 'center', marginBottom: 8,
          }}>
            {error}
          </div>
        )}

        {/* Secondary CTA */}
        <button
          onClick={onDismiss}
          style={{
            width: '100%', background: 'none', border: 'none',
            cursor: 'pointer', fontFamily: body, fontSize: 13,
            color: tokens.color.textSecondary, padding: '10px 16px',
            textAlign: 'center',
          }}
        >
          {trigger.secondary}
        </button>
      </div>

      {/* Keyframe animations */}
      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }
        @keyframes pulse {
          0%, 100% { opacity: 0.5; transform: translateX(-50%) scale(1); }
          50% { opacity: 1; transform: translateX(-50%) scale(1.1); }
        }
      `}</style>
    </div>
  );
}
