/* ═══════════════════════════════════════════════════════════════════════════
   useConversionTriggers — Paper Trading → Live Trading conversion hook
   Tracks user milestones and triggers upgrade prompts at optimal moments.

   Triggers:
   1. First profitable trade (immediate dopamine)
   2. After 5-10 trades (system proven)
   3. After ~24h of paper trading (commitment built)
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useCallback } from 'react';
import { getUserTier, TIER_LEVELS } from './useTierGate';

const TRIGGER_KEY = 'aura_conversion_triggers';

function loadState() {
  try { return JSON.parse(localStorage.getItem(TRIGGER_KEY) || '{}'); } catch { return {}; }
}

function saveState(s) {
  localStorage.setItem(TRIGGER_KEY, JSON.stringify(s));
}

export default function useConversionTriggers() {
  const tier = getUserTier();
  const isPaid = (TIER_LEVELS[tier] ?? 0) >= (TIER_LEVELS.trader ?? 1);
  const [trigger, setTrigger] = useState(null);

  const checkTriggers = useCallback((paperData) => {
    if (isPaid) return; // Already converted — no nudges needed

    const s = loadState();

    // Trigger 1: First profitable trade
    const trades = paperData?.trades || [];
    if (!s.firstProfitShown && trades.some(t => (t.pnl || t.realized_pnl || 0) > 0)) {
      s.firstProfitShown = true;
      saveState(s);
      setTrigger({
        type: 'first_profit',
        title: 'Your First Profitable Trade',
        body: 'The system just generated a winning trade in paper mode. This is the same signal engine that runs with real capital.',
        cta: 'Deploy Real Capital',
        secondary: 'Continue Paper Trading',
      });
      return;
    }

    // Trigger 2: After 5+ trades executed
    const tradeCount = trades.length || paperData?.trade_count || paperData?.total_trades || 0;
    if (!s.fiveTradesShown && tradeCount >= 5) {
      const winCount = trades.filter(t => (t.pnl || t.realized_pnl || 0) > 0).length;
      const winRate = tradeCount > 0 ? ((winCount / tradeCount) * 100).toFixed(0) : 0;
      s.fiveTradesShown = true;
      s.fiveTradesStats = { tradeCount, winRate };
      saveState(s);
      setTrigger({
        type: 'five_trades',
        title: 'System Proven',
        body: `${tradeCount} trades executed. The execution engine is working. The risk engine is protecting. Upgrade to deploy real capital and start compounding.`,
        cta: 'Enable Live Trading',
        secondary: 'Continue Paper Trading',
        stats: { tradeCount, winRate },
      });
      return;
    }

    // Trigger 3: After 24h of paper trading
    if (!s.paperStartedAt) {
      s.paperStartedAt = Date.now();
      saveState(s);
    }
    const hoursActive = (Date.now() - s.paperStartedAt) / 3600000;
    if (!s.dayOneShown && hoursActive >= 24) {
      s.dayOneShown = true;
      saveState(s);
      setTrigger({
        type: 'day_one',
        title: 'The System Runs Without You',
        body: "You've been paper trading for 24 hours. The system scanned, executed, and managed risk — while you did other things. That's the point. Upgrade to compound real capital.",
        cta: 'Start Compounding Capital',
        secondary: 'Continue Paper Trading',
        hoursActive: Math.floor(hoursActive),
      });
      return;
    }
  }, [isPaid]);

  const dismiss = useCallback(() => setTrigger(null), []);

  return { trigger, checkTriggers, dismiss, isPaid };
}
